import React, { ReactElement, useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { Animator } from '@arwes/react-animator';
import { Puffs } from '@arwes/react-bgs';

const Sandbox = (): ReactElement => {
  const [active, setActive] = useState(true);

  useEffect(() => {
    const iid = setInterval(() => setActive(active => !active), 3000);
    return () => clearInterval(iid);
  }, []);

  return (
    <div style={{ position: 'relative', width: '80vw', height: '80vh' }}>
      <Puffs
        color='hsla(180, 100%, 75%, 0.5)'
        quantity={20}
        zIndex={100}
        style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%' }}
      />
      <Animator
        active={active}
        duration={{
          interval: 2
        }}
        style={{
          position: 'absolute',
          top: 0,
          left: 0,
          zIndex: 101
        }}
      >
        <div style={{ textAlign: 'center', color: 'white', paddingTop: '30%' }}>
          <h1 className="heading">ENTROPY WORSHIP</h1>
          <h1 className="panel info shown">Web Build 2.0.10.21.2024</h1>
        </div>
      </Animator>
    </div>
  );
};

createRoot(document.querySelector('#root')).render(<Sandbox />);
export default Sandbox;
